import re

def checkAdminPassword(password):
    if not password or len(password) < 8:
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[!@#$%^&*]', password):
        return False
    if any(c.isspace() for c in password):
        return False
    return True

